import{_ as t,o as r,c as s,j as e,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"星火翼·陨落之舞","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/星火翼·陨落之舞.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/星火翼·陨落之舞.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/星火翼·陨落之舞.md"};function d(_,a,l,i,c,h){return r(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"星火翼·陨落之舞",tabindex:"-1"},[n("星火翼·陨落之舞 "),e("a",{class:"header-anchor",href:"#星火翼·陨落之舞","aria-label":'Permalink to "星火翼·陨落之舞"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),p('<h1 id="星火翼·陨落之舞-1" tabindex="-1">星火翼·陨落之舞 <a class="header-anchor" href="#星火翼·陨落之舞-1" aria-label="Permalink to &quot;星火翼·陨落之舞&quot;">​</a></h1><p>星火翼·陨落之舞</p><p>D+1500</p><p>科技本质</p><p>又名单兵突入大气层装置。星火翼·陨落之舞在平时呈现为一个精巧的装置，外形像是一个小巧的双肩背饰，使用者可以根据需求灵活调整其外形。装置实际由光滑的黑色魔法合金构成，表面镶嵌着的微小符文与复杂的能量流通管道，只有在激活时会显露出能量流光，整体造型十分便于携带。在使用者启动时，背部结构会迅速展开，像羽翼一般的光翼装置立刻从背后延展，带着星辰般的光辉，释放出耀眼的蓝紫色流光。</p><p>星火升腾术：这一术式是装备的核心，消耗1点意志，使用者借助此术式瞬间获得强大的垂直上升力量，使用者会在10分钟时间内逐渐加速至500公里/小时的速度，并以这个速度迅猛冲向高空。光翼的展开产生炫目的光辉，宛如流星拖曳着闪烁的光尾，穿越层云，突破大气层。在地球环境时，此术式可以让使用者上升至大气稀薄的逃逸层的下缘，即500公里的高度，其他非地球环境则需要st进行判定。因为能量的巨大消耗和复杂的准备，此术式每天只能使用一次，且仅能在战斗外使用。</p><p>滑翔功能：<br> 再入稠密大气层时，装备的光翼则会展现出极强的滑翔能力。使用者如同流星般从高空降落，与空气摩擦出的光点跟随使用者的尾迹飘散，宛如星辰般在空中划出绚烂轨迹。滑翔模式下，光翼利用气流的控制将速度减缓，允许使用者进行优雅的滑行。下落起点为10公里以上时，滑翔进入高速模式，最大垂直降落速率将达到为130m/s，几乎与上升速度相等。在此过程中，每降低1米的高度，使用者便可水平飞行2米——这意味着从500公里的降落高度，使用者可水平滑翔1000公里。降落过程中产生的高温和气流摩擦会让使用者无法与其他空中物体互动；但若在低空正常滑翔，速度会逐渐平稳，水平的滑翔速度将为使用者的移动速度。</p><p>三防与呼吸装置：<br> 由于高空环境的极端条件，星火翼·陨落之舞配备了强大的三防系统，能够有效抵御太空环境的极端条件与空气摩擦带来的剧烈高温。装备会自动启动防护机制，发出微弱光辉，形成护盾保护使用者的身体。在高空时，内置的呼吸装置也会自动激活，确保使用者可以顺利呼吸，避免窒息。使用者获得【三防】能力，且无需依赖外部空气进行呼吸。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=t(o,[["render",d]]);export{f as __pageData,m as default};
